<?php
/**
 * Deploy autocontenuto: Prezzo di Listino + Prezzo Codice su righe contratto.
 * Marker: quote-item-catalog-prices-php-20260606
 *
 * Uso (in ~/public_html/crm/mec-group):
 *   curl -fsSL "URL/tools/applica-quote-item-catalog-prices.php?t=$(date +%s)" -o /tmp/applica-quote-item-catalog-prices.php
 *   php /tmp/applica-quote-item-catalog-prices.php
 */

declare(strict_types=1);

$marker = 'quote-item-catalog-prices-php-20260606';
$root = getenv('CRM_ROOT') ?: (getenv('HOME') . '/public_html/crm/mec-group');

if (!is_dir($root)) {
    fwrite(STDERR, "ERRORE: cartella CRM non trovata: {$root}\n");
    exit(1);
}

chdir($root);

$files = json_decode(<<<'JSON'
{"custom/Espo/Custom/Services/QuotePricingCalculator.php":"","custom/Espo/Custom/Tools/Quote/Api/PostGetItemCatalogPrices.php":"","custom/Espo/Custom/Resources/routes.json":"WwogICAgewogICAgICAgICJyb3V0ZSI6ICJRdW90ZS9nZXRJdGVtQ2F0YWxvZ1ByaWNlcyIsCiAgICAgICAgIm1ldGhvZCI6ICJwb3N0IiwKICAgICAgICAiYWN0aW9uQ2xhc3NOYW1lIjogIkVzcG9cXEN1c3RvbVxcVG9vbHNcXFF1b3RlXFxBcGlcXFBvc3RHZXRJdGVtQ2F0YWxvZ1ByaWNlcyIKICAgIH0KXQo=","custom/Espo/Custom/Resources/client/custom/src/views/quote/fields/item-list.js":"","custom/Espo/Custom/Resources/client/custom/src/views/quote/record/item.js":"","client/custom/src/views/quote/fields/item-list.js":"","client/custom/src/views/quote/record/item.js":""}
JSON, true, 512, JSON_THROW_ON_ERROR);

$ts = date('Ymd-His');
$bk = "custom/backup-layouts/quote-item-catalog-prices-{$ts}";
@mkdir($bk, 0755, true);

echo "=== Backup ({$marker}) ===\n";
foreach (array_keys($files) as $rel) {
    $src = $root . '/' . $rel;
    if (is_file($src)) {
        @copy($src, $bk . '/' . basename($rel));
    }
}
echo "Backup: {$bk}/\n\n";

echo "=== Scrivo file ({$marker}) ===\n";
foreach ($files as $rel => $b64) {
    $dest = $root . '/' . $rel;
    $dir = dirname($dest);
    if (!is_dir($dir) && !mkdir($dir, 0755, true) && !is_dir($dir)) {
        fwrite(STDERR, "ERRORE: impossibile creare cartella {$dir}\n");
        exit(1);
    }
    $bytes = file_put_contents($dest, base64_decode($b64, true));
    if ($bytes === false) {
        fwrite(STDERR, "ERRORE: impossibile scrivere {$rel}\n");
        exit(1);
    }
    echo "OK {$rel} ({$bytes} bytes)\n";
}

echo "\n=== Verifica PHP ===\n";
passthru('php -l custom/Espo/Custom/Services/QuotePricingCalculator.php', $c1);
passthru('php -l custom/Espo/Custom/Tools/Quote/Api/PostGetItemCatalogPrices.php', $c2);
if ($c1 !== 0 || $c2 !== 0) {
    exit(1);
}

echo "\n=== Rebuild EspoCRM ===\n";
passthru('php command.php rebuild', $c3);
passthru('php command.php clear-cache 2>/dev/null || true');
@array_map('unlink', glob('data/cache/*') ?: []);

echo "\nDeploy completato ({$marker}).\n";
echo "Ctrl+F5 nel browser, poi test contratto + prodotto.\n";
